function validateUser(user) {
  if (typeof user.name !== 'string' || user.name.trim() === '') {
    throw new Error('Invalid name: must be a non-empty string.');
  }

  if (!Number.isInteger(user.age) || user.age <= 0) {
    throw new Error('Invalid age: must be a positive integer.');
  }

  // Simple email regex for demonstration
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (typeof user.email !== 'string' || !emailRegex.test(user.email)) {
    throw new Error('Invalid email: must be a valid email address.');
  }

  return true; // validation passed
}

try {
  const newUser = {
    name: 'Alice',
    age: 30,
    email: 'alice@example.com'
  };
  validateUser(newUser);
  console.log('User is valid!');
} catch (error) {
  console.error('User validation failed:', error.message);
}

try {
  const badUser = {
    name: '',
    age: -5,
    email: 'not-an-email'
  };
  validateUser(badUser);
} catch (error) {
  console.error('User validation failed:', error.message);
}

